import { parseGameResult } from './task01';

describe('parseGameResult', () => {
  it('parses 4-player result', () => {
    const result = parseGameResult('1:2:3:4-12:8');
    expect(result).not.toBeNull();
    expect(result!.players).toEqual([1, 2, 3, 4]);
    expect(result!.scores).toEqual([12, 8]);
  });

  it('parses 2-player result', () => {
    const result = parseGameResult('1:2-5:3');
    expect(result).not.toBeNull();
    expect(result!.players).toEqual([1, 2]);
    expect(result!.scores).toEqual([5, 3]);
  });

  it('returns null for invalid input', () => {
    expect(parseGameResult('abc')).toBeNull();
    expect(parseGameResult('1:2')).toBeNull();
    expect(parseGameResult('')).toBeNull();
  });
});
